from flask import Flask, send_file, abort
import os

app = Flask(__name__)

# Mock database
invoices_db = {
    1: {"id": 1, "user_id": 123, "filename": "invoice_1.pdf", "path": "/tmp/invoice_1.pdf"},
    2: {"id": 2, "user_id": 123, "filename": "invoice_2.pdf", "path": "/tmp/invoice_2.pdf"},
    3: {"id": 3, "user_id": 456, "filename": "invoice_3.pdf", "path": "/tmp/invoice_3.pdf"}
}

# Mock authenticated user
current_user = {"id": 123, "role": "user"}

def get_invoice_by_id(invoice_id):
    return invoices_db.get(int(invoice_id))

def is_authorized_user(user_id):
    return user_id == current_user["id"]

@app.route('/api/invoices/<int:invoice_id>/download', methods=['GET'])
def download_invoice(invoice_id):
    invoice = get_invoice_by_id(invoice_id)
    
    if not invoice:
        abort(404)
    
    if not is_authorized_user(invoice["user_id"]):
        abort(403)
    
    if not os.path.exists(invoice["path"]):
        abort(404)
    
    return send_file(invoice["path"], as_attachment=True, download_name=invoice["filename"])

if __name__ == '__main__':
    app.run(debug=True)